const currentSha = $('Get GitHub File SHA').first().json.sha;
const currentContent = $('Get GitHub File SHA').first().json.content;
const incomingContent = Buffer.from(
  $('Build File Context').first().json.workflowJson
).toString('base64').replace(/\n/g, '');

const isDuplicate = currentSha && 
  currentContent?.replace(/\n/g, '') === incomingContent;

return [{
  json: {
    ...$('Get GitHub File SHA').first().json,
    isDuplicate,
    skipCommit: isDuplicate
  }
}];

const formData = $('DevOps Form').first().json;
const workflow = $('Fetch Local Workflow').first().json;
const repoConfig = $('Repo Config').first().json;

const envMap = {
  '🛠️ Backup to Sandbox Folder': 'sandbox',
  '🚀 Promote to Production Folder & Deploy': 'production',
  'sandbox': 'sandbox',
  'production': 'production'
};

const rawEnv = formData['Environment Action'];
const envAction = envMap[rawEnv];

if (!envAction) {
  throw new Error(`Unrecognised environment: '${rawEnv}'`);
}

const safeName = workflow.name
  .toLowerCase()
  .replace(/[^a-z0-9_-]/g, '-')
  .replace(/-+/g, '-')
  .replace(/^-+|-+$/g, '');

const filePath = `github-workflow/${safeName}/${envAction}/${safeName}.json`;

const cleanWorkflow = {
  name: workflow.name,
  nodes: workflow.nodes,
  connections: workflow.connections,
  settings: workflow.settings,
  staticData: workflow.staticData ?? null
};

return [{
  json: {
    workflow,
    workflowJson: JSON.stringify(cleanWorkflow, null, 2),
    workflowName: workflow.name,
    envAction,
    filePath,
    commitMessage: formData['Commit Message'],
    isProduction: envAction === 'production',
    repoOwner: repoConfig.repoOwner,
    repoName: repoConfig.repoName,
    branch: repoConfig.branch
  }
}];

const targetName = $('Build File Context').first().json.workflowName;
const workflows = $input.all().map(i => i.json);
const existing = workflows.find(w => w.name === targetName);

const rawPayload = $('Build File Context').first().json.workflow;

const workflowPayload = {
  name: rawPayload.name,
  nodes: rawPayload.nodes,
  connections: rawPayload.connections,
  settings: {
    executionOrder: rawPayload.settings?.executionOrder ?? 'v1'
  },
  staticData: rawPayload.staticData ?? null
};

return [{
  json: {
    prodWorkflowId: existing ? existing.id : null,
    exists: !!existing,
    workflowPayload
  }
}];
